'use client';

import { useState, ChangeEvent, FormEvent } from 'react';
import { supabase } from '@/lib/supabase';
import { UploadCloud, CheckCircle2, AlertCircle, Loader2, FileText } from 'lucide-react';

export default function PendaftaranPage() {
  // State untuk form input
  const [namaLengkap, setNamaLengkap] = useState('');
  const [posisiDilamar, setPosisiDilamar] = useState('');
  const [nomorStr, setNomorStr] = useState('');
  const [email, setEmail] = useState('');
  const [whatsapp, setWhatsapp] = useState('');
  const [fileCv, setFileCv] = useState<File | null>(null);

  // State untuk status submit
  const [loading, setLoading] = useState(false);
  const [sukses, setSukses] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // List posisi (bisa disesuaikan dengan kebutuhan RS Arun)
  const listPosisi = [
    'Dokter Umum',
    'Perawat',
    'Bidan',
    'Apoteker / Farmasi',
    'Staf Administrasi',
    'IT Support / Developer',
    'Radiografer',
    'Analis Kesehatan'
  ];

  const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      
      // 1. Validasi ukuran file (maksimal 2MB)
      if (selectedFile.size > 2 * 1024 * 1024) {
        setErrorMsg('Ukuran file maksimal 2MB.');
        setFileCv(null);
        return;
      }
      
      // 2. Validasi tipe file (PDF, JPG, JPEG, PNG)
      const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png'];
      if (!allowedTypes.includes(selectedFile.type)) {
        setErrorMsg('Format file harus PDF, JPG, atau PNG.');
        setFileCv(null);
        return;
      }

      setErrorMsg('');
      setFileCv(selectedFile);
    }
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');

    try {
      if (!fileCv) {
        throw new Error('Silakan unggah file CV Anda terlebih dahulu.');
      }

      // 1. Proses Upload CV ke Supabase Storage Bucket 'cv-pelamar'
      const fileExt = fileCv.name.split('.').pop();
      const uniqueFileName = `${Date.now()}-${Math.random().toString(36).substring(2, 9)}.${fileExt}`;
      
      const { data: uploadData, error: uploadError } = await supabase.storage
        .from('cv-pelamar')
        .upload(uniqueFileName, fileCv);

      if (uploadError) throw uploadError;

      // 2. Ambil Public URL dari file yang diunggah
      const { data: publicUrlData } = supabase.storage
        .from('cv-pelamar')
        .getPublicUrl(uniqueFileName);

      const cvUrl = publicUrlData.publicUrl;

      // 3. Simpan data pelamar ke tabel 'pelamar'
      const { error: insertError } = await supabase.from('pelamar').insert([
        {
          nama_lengkap: namaLengkap,
          posisi_dilamar: posisiDilamar,
          nomor_str: nomorStr || null, // Opsional jika posisi non-nakes
          email,
          whatsapp,
          cv_url: cvUrl,
          status: 'Pending'
        }
      ]);

      if (insertError) throw insertError;

      // Jika berhasil
      setSukses(true);
    } catch (err: any) {
      setErrorMsg(err.message || 'Terjadi kesalahan saat mengirim data.');
    } finally {
      setLoading(false);
    }
  };

  if (sukses) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-sm max-w-md w-full text-center border border-slate-100">
          <CheckCircle2 className="w-16 h-16 text-emerald-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Pendaftaran Berhasil!</h2>
          <p className="text-slate-600 mb-6 text-sm">
            Terima kasih telah melamar di RS Arun Lhokseumawe. Data dan berkas Anda telah aman tersimpan di sistem kami. Tim HRD akan segera meninjau berkas Anda.
          </p>
          <button 
            onClick={() => window.location.reload()} 
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-2.5 px-4 rounded-xl transition duration-200"
          >
            Kirim Lamaran Baru
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-xl mx-auto bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        
        {/* Header Rumah Sakit */}
        <div className="bg-emerald-600 p-6 text-white text-center">
          <h1 className="text-xl font-bold tracking-wide uppercase">E-Recruitment</h1>
          <p className="text-emerald-100 text-xs mt-1 font-light">Rumah Sakit Arun Lhokseumawe</p>
        </div>

        {/* Form Isi */}
        <form onSubmit={handleSubmit} className="p-6 sm:p-8 space-y-5">
          <p className="text-xs text-slate-400 font-medium">Silakan lengkapi formulir di bawah ini dengan data yang valid.</p>

          {errorMsg && (
            <div className="bg-rose-50 text-rose-600 p-3 rounded-xl flex items-start gap-2 text-xs border border-rose-100">
              <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
              <span>{errorMsg}</span>
            </div>
          )}

          {/* Nama Lengkap */}
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Nama Lengkap</label>
            <input
              type="text"
              required
              value={namaLengkap}
              onChange={(e) => setNamaLengkap(e.target.value)}
              placeholder="Masukkan nama lengkap sesuai KTP"
              className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition duration-150"
            />
          </div>

          {/* Posisi Dilamar */}
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Posisi yang Dilamar</label>
            <select
              required
              value={posisiDilamar}
              onChange={(e) => setPosisiDilamar(e.target.value)}
              className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition duration-150"
            >
              <option value="">-- Pilih Posisi --</option>
              {listPosisi.map((posisi) => (
                <option key={posisi} value={posisi}>{posisi}</option>
              ))}
            </select>
          </div>

          {/* Nomor STR (Kondisional/Opsional) */}
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">
              Nomor STR <span className="text-slate-400 font-normal lowercase">(Kosongkan jika non-nakes)</span>
            </label>
            <input
              type="text"
              value={nomorStr}
              onChange={(e) => setNomorStr(e.target.value)}
              placeholder="Contoh: 123456789 (Jika ada)"
              className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition duration-150"
            />
          </div>

          {/* Grid Email & WhatsApp */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Email Aktif</label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="nama@email.com"
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition duration-150"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Nomor WhatsApp</label>
              <input
                type="tel"
                required
                value={whatsapp}
                onChange={(e) => setWhatsapp(e.target.value)}
                placeholder="081234xxxxxx"
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition duration-150"
              />
            </div>
          </div>

          {/* Upload CV */}
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Unggah berkas CV (Format PDF, Maks 2MB)</label>
            <div className="relative border-2 border-dashed border-slate-200 hover:border-emerald-500 bg-slate-50 rounded-xl p-4 text-center cursor-pointer transition duration-150">
              <input
              type="file"
              required
              accept="application/pdf, image/jpeg, image/png" // Diubah di sini
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
              {!fileCv ? (
                <div className="space-y-1 text-slate-500">
                  <UploadCloud className="w-8 h-8 mx-auto text-slate-400" />
                  <p className="text-xs font-medium">Klik atau drop file PDF Anda di sini</p>
                </div>
              ) : (
                <div className="flex items-center justify-center gap-2 text-emerald-600">
                  <FileText className="w-5 h-5" />
                  <span className="text-xs font-semibold truncate max-w-[250px]">{fileCv.name}</span>
                </div>
              )}
            </div>
          </div>

          {/* Tombol Submit */}
          <button
            type="submit"
            disabled={loading}
            className="w-full mt-2 bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-300 text-white font-semibold py-3 px-4 rounded-xl transition duration-150 flex items-center justify-center gap-2 shadow-sm text-sm"
          >
            {loading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                <span>Memproses pendaftaran...</span>
              </>
            ) : (
              <span>Kirim Lamaran Sekarang</span>
            )}
          </button>

        </form>
      </div>
    </div>
  );
}